def fused_cholesky_solve(A: torch.Tensor, b: torch.Tensor) -> torch.Tensor:
    n, k = b.shape
    assert A.shape == (n, n), "Matrix A must be n x n"

    # Allocate output tensor
    x = torch.empty_like(b)

    # Launch kernel
    grid = (1, 1)
    _cholesky_solve_kernel[grid](A, b, x, n, k)

    return x

@triton.jit
def _cholesky_solve_kernel(A_ptr, b_ptr, x_ptr, n, k, BLOCK_SIZE: tl.constexpr = 128):
    # Shared memory for the Cholesky factor
    L = tl.shared_ptr(tl.float32, shape=(n, n))

    # Initialize L with A
    for i in range(n):
        for j in range(n):
            if i >= j:
                L[i, j] = tl.load(A_ptr + i * n + j)
            else:
                L[i, j] = 0.0

    # Cholesky decomposition
    for i in range(n):
        # Compute diagonal element
        sum_diag = 0.0
        for k_idx in range(i):
            sum_diag += L[i, k_idx] * L[i, k_idx]
        L[i, i] = tl.sqrt(L[i, i] - sum_diag)

        # Compute off-diagonal elements
        for j in range(i + 1, n):
            sum_off_diag = 0.0
            for k_idx in range(i):
                sum_off_diag += L[j, k_idx] * L[i, k_idx]
            L[j, i] = (L[j, i] - sum_off_diag) / L[i, i]

    # Forward substitution: L * y = b
    y = tl.shared_ptr(tl.float32, shape=(n, k))
    for i in range(n):
        for j in range(k):
            sum_y = 0.0
            for l in range(i):
                sum_y += L[i, l] * y[l, j]
            y[i, j] = (tl.load(b_ptr + i * k + j) - sum_y) / L[i, i]

    # Backward substitution: L.T * x = y
    for i in range(n - 1, -1, -1):
        for j in range(k):
            sum_x = 0.0
            for l in range(i + 1, n):
                sum_x += L[l, i] * tl.load(x_ptr + l * k + j)
            tl.store(x_ptr + i * k + j, (y[i, j] - sum_x) / L[i, i])

